import React from 'react';
import { Select } from '@linm-soft/common-components';
import { formatMoneyVnd } from '../../../../../utils/formatters';
import { purchaseInvoiceFormLabels } from '../../../../../constants/purchaseInvoiceFormLabels';
import type { usePurchaseInvoiceFormController } from '../hooks/usePurchaseInvoiceFormController';

type Vm = ReturnType<typeof usePurchaseInvoiceFormController>;

export const PurchaseInvoiceFooterSection: React.FC<{ vm: Vm }> = ({ vm }) => {
  const df = vm.styles;
  const {
    tid,
    fieldLock,
    processingLevel,
    setProcessingLevel,
    processingOpts,
    totalAmount,
  } = vm;

  const { viewSectionClass, selectDisabled } = fieldLock;

  return (
    <div className={[df.footer, viewSectionClass].filter(Boolean).join(' ')} data-testid={tid('section-footer')}>
      <div className={df.footerLeft}>
        <label className={df.label}>{purchaseInvoiceFormLabels.processingLevel}</label>
        <Select
          data-testid={tid('field-processingLevel')}
          options={processingOpts}
          value={processingLevel}
          onChange={(e: React.ChangeEvent<HTMLSelectElement>) => setProcessingLevel(e.target.value)}
          disabled={selectDisabled}
          title={selectDisabled ? 'Chỉ xem — nhấn Sửa để đổi mức xử lý' : undefined}
        />
      </div>
      <div className={df.totalBlock}>
        <span className={df.totalLabel}>{purchaseInvoiceFormLabels.totalLabel}:</span>
        <span className={df.totalValue}>{formatMoneyVnd(totalAmount)}</span>
      </div>
    </div>
  );
};
