import React from 'react';
import { VoucherFormToolbar, VoucherFormStatusGroup } from '../../../../../components/voucher';
import { ValidationErrorBanner } from '../../../../../components/layout';
import { formatProcessingLevelFromOptions } from '../../../../../utils/voucherProcessingLevelOptions';
import type { PurchaseInvoiceFormProps } from '../types/purchaseInvoice.types';
import { usePurchaseInvoiceFormController } from '../hooks/usePurchaseInvoiceFormController';
import { PurchaseInvoiceHeaderSection } from './PurchaseInvoiceHeaderSection';
import { PurchaseInvoiceLinesSection } from './PurchaseInvoiceLinesSection';
import { PurchaseInvoiceFooterSection } from './PurchaseInvoiceFooterSection';
import { PurchaseInvoiceFormModals } from './PurchaseInvoiceFormModals';

export const PurchaseInvoiceFormParent: React.FC<PurchaseInvoiceFormProps> = props => {
  const vm = usePurchaseInvoiceFormController(props);
  const df = vm.styles;

  if (vm.showInitialLoading) {
    return (
      <div className={df.loading} data-testid={vm.tid('loading')}>
        Đang tải...
      </div>
    );
  }

  const {
    cfg,
    title,
    isNew,
    code,
    status,
    processingLevel,
    processingOpts,
    toolbarMode,
    isStatusLocked,
    isViewMode,
    saving,
    posting,
    saveLabel,
    showPostButton,
    hasSearchNav,
    searchNavIndex,
    searchResultIds,
    navigateToSearchId,
    handleBack,
    setShowApproveModal,
    setShowPostModal,
    handleCopy,
    setShowPrintModal,
    setShowSearchSlideout,
    handleNew,
    handleEdit,
    handleSave,
    handleCancel,
    setShowDeleteModal,
    toolbarDisabledReasons,
    validationErrors,
    bannerClosed,
    bannerExpanded,
    setBannerExpanded,
    setBannerClosed,
    validationBannerId,
  } = vm;

  const processingLevelLabel = formatProcessingLevelFromOptions(processingLevel, processingOpts);
  const canActOnDraft = !isNew && status === 'Draft' && !isStatusLocked;

  return (
    <div className={df.page} data-testid={vm.tid('form')}>
      <div className={df.stickyTop}>
        <VoucherFormToolbar
          testIdPrefix={cfg.testIdPrefix}
          title={isNew ? `Tạo ${title}` : `${title} — ${code || '...'}`}
          processingLevelBadge={
            !isNew ? <VoucherFormStatusGroup processingLevelLabel={processingLevelLabel} /> : undefined
          }
          formMode={toolbarMode}
          showViewHint={isViewMode && !isStatusLocked}
          canApprove={canActOnDraft}
          showPostButton={showPostButton}
          canPost={canActOnDraft && showPostButton}
          canCopy={!isNew}
          canPrint={!isNew}
          canEdit={!isNew && !isStatusLocked}
          canDelete={canActOnDraft}
          saving={saving}
          posting={posting}
          saveLabel={saveLabel}
          disabledReasons={toolbarDisabledReasons}
          searchNav={
            hasSearchNav
              ? {
                  index: searchNavIndex,
                  total: searchResultIds.length,
                  onFirst: () => navigateToSearchId(searchResultIds[0]),
                  onPrev: () => navigateToSearchId(searchResultIds[searchNavIndex - 1]),
                  onNext: () => navigateToSearchId(searchResultIds[searchNavIndex + 1]),
                  onEnd: () => navigateToSearchId(searchResultIds[searchResultIds.length - 1]),
                }
              : undefined
          }
          onBack={handleBack}
          onApprove={() => setShowApproveModal(true)}
          onPost={() => setShowPostModal(true)}
          onCopy={handleCopy}
          onPrint={() => setShowPrintModal(true)}
          onSearch={() => setShowSearchSlideout(true)}
          onNew={handleNew}
          onEdit={handleEdit}
          onSave={handleSave}
          onCancel={handleCancel}
          onDelete={() => setShowDeleteModal(true)}
        />
        {isStatusLocked && (
          <div className={df.readOnlyHint} style={{ margin: '0 16px 12px' }}>
            <i className="fas fa-lock" /> Chỉ xem — đã ghi sổ hoặc mức xử lý cuối
          </div>
        )}
      </div>

      <ValidationErrorBanner
        errors={validationErrors}
        closed={bannerClosed}
        expanded={bannerExpanded}
        onToggle={() => setBannerExpanded(v => !v)}
        onClose={() => setBannerClosed(true)}
        bannerId={validationBannerId}
      />

      <PurchaseInvoiceHeaderSection vm={vm} />
      <PurchaseInvoiceLinesSection vm={vm} />
      <PurchaseInvoiceFooterSection vm={vm} />

      <PurchaseInvoiceFormModals vm={vm} />
    </div>
  );
};
