    supplierId,
    supplierCode,
    supplierName,
    setSupplierId,
    setSupplierCode,
    setSupplierName,
    creditAccountCode,
    creditAccountName,
    vatAccountCode,
    vatAccountName,
    setCreditAccountCode,
    setCreditAccountName,
    setVatAccountCode,
    setVatAccountName,
    fieldErrors,
    patchHeaderFieldError,
    lines,
